function renderTablaAgentes() {
    const tbody = document.getElementById('tabla-agentes');
    if (!tbody) return;
    
    tbody.innerHTML = '';
    const agentesReversos = [...dbAgentes].reverse();
    
    if (agentesReversos.length === 0) {
        tbody.innerHTML = `<tr><td class="text-center text-muted small py-4">Aún no hay organizaciones inscritas.</td></tr>`;
    } else {
        agentesReversos.forEach(agente => {
            const tr = document.createElement('tr');
            tr.innerHTML = `
                <td class="fw-semibold text-dark p-3">
                    ${agente.organizacion}<br>
                    <span class="badge bg-primary bg-opacity-10 text-primary border border-primary-subtle rounded-pill mt-2 mb-1">${agente.zona}</span><br>
                    <small class="text-secondary"><i class="fas fa-user text-muted me-1"></i> ${agente.representante}</small>
                </td>
            `;
            tbody.appendChild(tr);
        });
    }
    
    // Renderizar gráfico
    renderZonasChart();
    renderAgentesZonaChart();
}

let agentesZonaChartInstance = null;

function renderAgentesZonaChart() {
    const ctx = document.getElementById('agentesZonaChart');
    if (!ctx) return;

    const conteoZonas = {};
    dbAgentes.forEach(agente => {
        if (!conteoZonas[agente.zona]) {
            conteoZonas[agente.zona] = 0;
        }
        conteoZonas[agente.zona]++;
    });

    const labelsOriginales = Object.keys(conteoZonas).sort();
    const labels = labelsOriginales.map(l => l.replace('Zona ', 'Z'));
    const data = labelsOriginales.map(label => conteoZonas[label]);

    if (agentesZonaChartInstance) {
        agentesZonaChartInstance.destroy();
    }

    const canvasContenedor = ctx.parentElement;
    let emptyMsg = document.getElementById('empty-agentes-chart-msg');
    
    if (data.length === 0) {
        ctx.style.display = 'none';
        if (!emptyMsg) {
            emptyMsg = document.createElement('div');
            emptyMsg.id = 'empty-agentes-chart-msg';
            emptyMsg.className = 'text-center text-muted py-5 small';
            emptyMsg.innerHTML = 'Aún no hay agentes inscritos.';
            canvasContenedor.appendChild(emptyMsg);
        } else {
            emptyMsg.style.display = 'block';
        }
        return;
    } else {
        ctx.style.display = 'block';
        if (emptyMsg) emptyMsg.style.display = 'none';
    }

    const bgColors = [
        'rgba(54, 162, 235, 0.8)',   // Azul
        'rgba(255, 99, 132, 0.8)',   // Rojo/Rosa
        'rgba(255, 206, 86, 0.8)',   // Amarillo
        'rgba(75, 192, 192, 0.8)',   // Verde agua
        'rgba(153, 102, 255, 0.8)',  // Morado
        'rgba(255, 159, 64, 0.8)',   // Naranja
        'rgba(199, 199, 199, 0.8)',  // Gris
        'rgba(233, 30, 99, 0.8)',    // Fucsia
        'rgba(0, 188, 212, 0.8)',    // Cian
        'rgba(139, 195, 74, 0.8)',   // Verde claro
        'rgba(255, 87, 34, 0.8)',    // Naranja oscuro
        'rgba(103, 58, 183, 0.8)',   // Violeta oscuro
        'rgba(0, 150, 136, 0.8)',    // Cerceta
        'rgba(121, 85, 72, 0.8)'     // Marrón
    ];

    if (typeof ChartDataLabels !== 'undefined') {
        Chart.register(ChartDataLabels);
    }

    agentesZonaChartInstance = new Chart(ctx, {
        type: 'bar',
        data: {
            labels: labels,
            datasets: [{
                label: 'Agentes Inscritos',
                data: data,
                backgroundColor: bgColors.slice(0, data.length),
                borderWidth: 1
            }]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            plugins: {
                legend: {
                    display: false
                },
                datalabels: {
                    color: '#fff',
                    anchor: 'end',
                    align: 'bottom',
                    font: {
                        weight: 'bold',
                        size: 11
                    }
                }
            },
            scales: {
                y: {
                    beginAtZero: true,
                    ticks: {
                        stepSize: 1
                    }
                }
            }
        }
    });
}

let zonasChartInstance = null;

function renderZonasChart() {
    const ctx = document.getElementById('zonasChart');
    if (!ctx) return;

    // Sumar las iniciativas registradas en el Radar
    const conteoZonas = {};
    dbProyectos.forEach(proyecto => {
        if (!conteoZonas[proyecto.zona]) {
            conteoZonas[proyecto.zona] = 0;
        }
        conteoZonas[proyecto.zona]++;
    });

    // Extraer solo las zonas que tienen al menos 1 proyecto y abreviarlas (ej. Zona 01 -> Z01)
    const labels = Object.keys(conteoZonas).map(zona => zona.replace(/Zona\s+/i, 'Z'));
    const data = Object.values(conteoZonas);

    // Destruir la instancia anterior si existe para poder re-dibujar
    if (zonasChartInstance) {
        zonasChartInstance.destroy();
    }

    const canvasContenedor = ctx.parentElement;
    let emptyMsg = document.getElementById('empty-chart-msg');
    
    if (data.length === 0) {
        ctx.style.display = 'none';
        if (!emptyMsg) {
            emptyMsg = document.createElement('div');
            emptyMsg.id = 'empty-chart-msg';
            emptyMsg.className = 'text-center text-muted py-5 small';
            emptyMsg.innerHTML = 'Aún no hay iniciativas en el Radar.';
            canvasContenedor.appendChild(emptyMsg);
        } else {
            emptyMsg.style.display = 'block';
        }
        return;
    } else {
        ctx.style.display = 'block';
        if (emptyMsg) emptyMsg.style.display = 'none';
    }

    // 14 Colores modernos y únicos para el gráfico (uno para cada zona potencial)
    const bgColors = [
        'rgba(54, 162, 235, 0.8)',   // Azul
        'rgba(255, 99, 132, 0.8)',   // Rojo/Rosa
        'rgba(255, 206, 86, 0.8)',   // Amarillo
        'rgba(75, 192, 192, 0.8)',   // Verde agua
        'rgba(153, 102, 255, 0.8)',  // Morado
        'rgba(255, 159, 64, 0.8)',   // Naranja
        'rgba(199, 199, 199, 0.8)',  // Gris
        'rgba(233, 30, 99, 0.8)',    // Fucsia
        'rgba(0, 188, 212, 0.8)',    // Cian
        'rgba(139, 195, 74, 0.8)',   // Verde claro
        'rgba(255, 87, 34, 0.8)',    // Naranja oscuro
        'rgba(103, 58, 183, 0.8)',   // Violeta oscuro
        'rgba(0, 150, 136, 0.8)',    // Cerceta
        'rgba(121, 85, 72, 0.8)'     // Marrón
    ];

    // Registrar el plugin de datalabels si está disponible
    if (typeof ChartDataLabels !== 'undefined') {
        Chart.register(ChartDataLabels);
    }

    zonasChartInstance = new Chart(ctx, {
        type: 'doughnut',
        data: {
            labels: labels,
            datasets: [{
                label: 'Iniciativas Registradas',
                data: data,
                backgroundColor: bgColors,
                borderWidth: 1
            }]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            plugins: {
                legend: {
                    position: 'right', // Mostrar leyenda a la derecha
                },
                datalabels: {
                    color: '#fff', // Color del texto del número
                    font: {
                        weight: 'bold',
                        size: 14
                    },
                    formatter: function(value, context) {
                        return value; // Retorna el número de agentes
                    }
                }
            }
        }
    });
}

function llenarEjemplo() {
    const nombres = ["María", "Jorge", "Luis", "Ana", "Carlos", "Elena", "Pedro", "Laura", "Diego", "Carmen", "Rosa", "Miguel", "Lucía", "Andrés"];
    const apellidos = ["Fernández", "Ramírez", "Gómez", "Pérez", "García", "López", "Martínez", "Sánchez", "Rodríguez", "Vásquez", "Flores", "Torres"];
    const profesiones = ["Arquitecto/a", "Ingeniero/a", "Abogado/a", "Médico/a", "Contador/a", "Docente", "Administrador/a", "Comerciante"];
    const organizaciones = ["Innova", "Unidos por", "Desarrollo de", "Frente de", "Asociación Vecinal"];
    
    const rName = () => `${nombres[Math.floor(Math.random() * nombres.length)]} ${apellidos[Math.floor(Math.random() * apellidos.length)]}`;
    const rDni = () => Math.floor(10000000 + Math.random() * 90000000).toString();
    const rCel = () => '9' + Math.floor(10000000 + Math.random() * 90000000).toString();
    const rDate = (startYear, endYear) => {
        const d = new Date(startYear + Math.random() * (endYear - startYear), Math.floor(Math.random() * 12), Math.floor(Math.random() * 28) + 1);
        return d.toISOString().split('T')[0];
    };
    const rProf = () => profesiones[Math.floor(Math.random() * profesiones.length)];

    // Organización
    document.getElementById('orgNombre').value = `${organizaciones[Math.floor(Math.random() * organizaciones.length)]} Miraflores ${Math.floor(Math.random()*100)}`;
    document.getElementById('orgZona').value = `Zona ${Math.floor(Math.random()*14 + 1).toString().padStart(2, '0')}`;
    document.getElementById('orgDomicilio').value = `Av. Principal ${Math.floor(Math.random() * 900 + 100)}`;
    document.getElementById('orgRUOS').value = `Res. ${Math.floor(Math.random() * 900 + 100)}-2024-MM`;
    document.getElementById('fecha-registro').value = rDate(2023, 2024);
    document.getElementById('orgFundacion').value = rDate(2010, 2022);
    document.getElementById('orgMiembros').value = Math.floor(Math.random() * 100 + 20).toString();
    document.getElementById('orgTipo').value = "Junta Vecinal";
    document.getElementById('orgNivel').value = "Local";
    document.getElementById('orgFines').value = "Promover el desarrollo sostenible, la seguridad ciudadana y la participación activa de los vecinos en la toma de decisiones.";
    
    // Vigencia
    document.getElementById('vigencia-inicio').value = rDate(2024, 2024);
    const endDate = new Date(document.getElementById('vigencia-inicio').value);
    endDate.setFullYear(endDate.getFullYear() + 2);
    document.getElementById('vigencia-termino').value = endDate.toISOString().split('T')[0];

    // Directiva
    document.getElementById('orgPresidente').value = rName();
    document.getElementById('orgPresidenteDNI').value = rDni();
    document.getElementById('orgPresidenteNacimiento').value = rDate(1960, 1990);
    
    document.getElementById('orgTesorero').value = rName();
    document.getElementById('orgTesoreroDNI').value = rDni();
    document.getElementById('orgTesoreroNacimiento').value = rDate(1960, 1990);

    // Representante Titular (Mismo Presidente en este ejemplo)
    const chkMismoPresidente = document.getElementById('chkMismoPresidente');
    if(chkMismoPresidente) {
        chkMismoPresidente.checked = true;
        // Disparar el evento change para que se copien los datos automáticamente
        chkMismoPresidente.dispatchEvent(new Event('change'));
    }

    const removeAccents = (str) => str.normalize("NFD").replace(/[\u0300-\u036f]/g, "");
    document.getElementById('repCelular').value = rCel();
    document.getElementById('repCorreo').value = removeAccents(document.getElementById('orgPresidente').value.split(' ')[0].toLowerCase()) + "@ejemplo.com";
    document.getElementById('repProfesion').value = rProf();
    document.getElementById('repInstruccion').value = "Universitario"; // Corregido: "Universitario" es un valor válido del select

    // Representante Alterno
    document.getElementById('altNombre').value = rName();
    document.getElementById('altDNI').value = rDni();
    document.getElementById('altNacimiento').value = rDate(1960, 1995);
    document.getElementById('altCelular').value = rCel();
    document.getElementById('altCorreo').value = removeAccents(document.getElementById('altNombre').value.split(' ')[0].toLowerCase()) + "@ejemplo.com";
    document.getElementById('altProfesion').value = rProf();
    document.getElementById('altCargo').value = "Secretario(a)";
    document.getElementById('altInstruccion').value = "Universitario";
    
    // Abrir todos los acordeones para que el usuario vea que se llenaron
    const collapseElements = document.querySelectorAll('.accordion-collapse');
    collapseElements.forEach(el => {
        const bsCollapse = new bootstrap.Collapse(el, { toggle: false });
        bsCollapse.show();
    });
}

