function buscarYRenovar() {
    const dniBuscado = document.getElementById('buscarDNI').value.trim();
    const contenedorResultado = document.getElementById('resultado-busqueda');
    
    if (!dniBuscado) {
        alert("Por favor ingresa un DNI para buscar.");
        return;
    }

    const agenteEncontrado = dbAgentes.find(a => a.dni === dniBuscado);

    if (agenteEncontrado) {
        contenedorResultado.classList.remove('d-none');
        contenedorResultado.innerHTML = `
            <h5 class="text-primary mb-3"><i class="fas fa-check-circle"></i> Organización Encontrada</h5>
            <p class="mb-1"><strong>Organización:</strong> ${agenteEncontrado.organizacion}</p>
            <p class="mb-1"><strong>Representante:</strong> ${agenteEncontrado.representante}</p>
            <p class="mb-1"><strong>Zona:</strong> ${agenteEncontrado.zona}</p>
            
            <div class="form-check my-3 p-3 bg-white border rounded shadow-sm d-flex align-items-center">
                <input class="form-check-input mt-0 me-3" type="checkbox" value="" id="checkRenovacion" style="transform: scale(1.5);">
                <label class="form-check-label fw-bold text-success" for="checkRenovacion">
                    ✅ Confirmo la participación de mi organización en el Presupuesto Participativo 2027
                </label>
            </div>
            
            <button class="btn btn-success fw-bold w-100 py-2" id="btnProcesarRenovacion">
                <i class="fas fa-sync-alt"></i> Renovar y Descargar PDF 2027
            </button>
        `;

        document.getElementById('btnProcesarRenovacion').addEventListener('click', () => {
            const isChecked = document.getElementById('checkRenovacion').checked;
            if (!isChecked) {
                alert("Debes confirmar la participación marcando la casilla correspondiente.");
                return;
            }
            agenteEncontrado.fecha = new Date().toLocaleDateString();
            generarPdfAgente(agenteEncontrado);
            alert("¡Renovación Exitosa! Descargando tu constancia 2027.");
            contenedorResultado.classList.add('d-none');
            document.getElementById('buscarDNI').value = '';
        });
    } else {
        contenedorResultado.classList.remove('d-none');
        contenedorResultado.innerHTML = `
            <div class="text-danger p-3 text-center">
                <i class="fas fa-exclamation-triangle fa-2x mb-2"></i><br>
                No encontramos ninguna organización registrada con el DNI <strong>${dniBuscado}</strong>.<br>Por favor, ve a la pestaña "Nuevo Registro".
            </div>
        `;
    }
}

