// Estado temporal del wizard y evidencias
let wizardDatos = { agente: null, resultado: null };
let miniMapa = null;
let miniMarker = null;
let coordsProyecto = { lat: -12.1211, lng: -77.0298 }; // Miraflores centro aprox
let fotosProblemaBase64 = [];
let fotosSolucionBase64 = [];

function initMiniMapa() {
    if (miniMapa) {
        miniMapa.invalidateSize();
        if (miniMarker) {
            miniMapa.setView(miniMarker.getLatLng(), miniMapa.getZoom());
        }
        return;
    }
    const mapContainer = document.getElementById('mini-mapa');
    if (!mapContainer) return;

    miniMapa = L.map('mini-mapa').setView([coordsProyecto.lat, coordsProyecto.lng], 16);
    L.tileLayer('https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png', {
        attribution: '&copy; OpenStreetMap contributors &copy; CARTO',
        subdomains: 'abcd',
        maxZoom: 19
    }).addTo(miniMapa);

    // Inject Zones GeoJSON to the minimap
    if (typeof geojsonLayer !== 'undefined' && geojsonLayer) {
        L.geoJSON(geojsonLayer.toGeoJSON(), {
            style: function () {
                return {
                    color: '#0d6efd',
                    weight: 2,
                    opacity: 0.6,
                    fillOpacity: 0.05
                };
            },
            onEachFeature: function(feature, layer) {
                if (feature.properties && feature.properties.text_sector) {
                    const zonaText = feature.properties.text_sector.replace("Zona 0", "Z").replace("Zona ", "Z");
                    layer.bindTooltip(zonaText, {
                        permanent: true,
                        direction: 'center',
                        className: 'zone-label-tooltip'
                    });
                }
            }
        }).addTo(miniMapa);
    }

    miniMarker = L.marker([coordsProyecto.lat, coordsProyecto.lng], { draggable: true }).addTo(miniMapa);
    miniMarker.on('dragend', function (e) {
        coordsProyecto = miniMarker.getLatLng();
    });
}

function procesarArchivosWizard() {
    const inputProb = document.getElementById('fotos-problema');
    const inputSol = document.getElementById('fotos-solucion');

    if (inputProb) {
        inputProb.addEventListener('change', (e) => {
            fotosProblemaBase64 = [];
            Array.from(e.target.files).slice(0, 2).forEach(file => {
                const reader = new FileReader();
                reader.onload = (ev) => fotosProblemaBase64.push(ev.target.result);
                reader.readAsDataURL(file);
            });
        });
    }

    if (inputSol) {
        inputSol.addEventListener('change', (e) => {
            fotosSolucionBase64 = [];
            Array.from(e.target.files).slice(0, 2).forEach(file => {
                const reader = new FileReader();
                reader.onload = (ev) => fotosSolucionBase64.push(ev.target.result);
                reader.readAsDataURL(file);
            });
        });
    }
}

// Inicializar los listeners de archivo una vez que cargue el DOM
document.addEventListener('DOMContentLoaded', () => {
    renderMuroHonor();

    procesarArchivosWizard();
});

// --- Navegación entre pasos ---
function wizardGoTo(step) {
    const idea = document.getElementById('ideaTexto');
    if (step === 3 && idea && idea.value.trim().length < 50) {
        idea.classList.add('is-invalid');
        return;
    }
    if (idea) idea.classList.remove('is-invalid');

    for (let i = 1; i <= 5; i++) { // Modificado a 5 pasos
        const panel = document.getElementById(`panel-${i}`);
        if(panel) panel.classList.add('d-none');
        const ws = document.getElementById(`ws-${i}`);
        if(ws) {
            ws.classList.remove('active', 'done');
            if (i < step) ws.classList.add('done');
        }
    }
    document.getElementById(`panel-${step}`).classList.remove('d-none');
    document.getElementById(`ws-${step}`).classList.add('active');

    for (let i = 1; i <= 4; i++) { // Modificado a 4 lineas
        const line = document.getElementById(`wl-${i}`);
        if (line) {
            if (i < step) line.classList.add('done');
            else line.classList.remove('done');
        }
    }

    // Inicializar o refrescar el mapa si entramos al paso 4 (Evidencias)
    if (step === 4) {
        setTimeout(() => initMiniMapa(), 200);
    }
}

// --- Paso 1: Validar DNI ---
function validarDniProyecto() {
    const dniInput = document.getElementById('dniProyecto');
    const feedback = document.getElementById('dni-feedback');
    const dni = dniInput.value.trim();

    if (!/^\d{8}$/.test(dni)) {
        feedback.innerHTML = `<div class="alert alert-warning py-2"><i class="fas fa-exclamation-triangle me-2"></i>Ingresa un DNI válido de 8 dígitos.</div>`;
        return;
    }

    const db = JSON.parse(localStorage.getItem('dbAgentes') || '[]');
    const agente = db.find(a => a.dni === dni);

    if (!agente) {
        feedback.innerHTML = `
            <div class="alert alert-danger py-2">
                <i class="fas fa-times-circle me-2"></i>
                <strong>DNI no encontrado.</strong> Debes estar registrado como Agente Participante para formular proyectos.
                <a href="#" class="alert-link ms-2" onclick="navigate('registro'); return false;">Inscribirme ahora →</a>
            </div>`;
        return;
    }

    wizardDatos.agente = agente;
    document.getElementById('agente-info-text').innerHTML =
        `<strong>¡Hola, ${agente.representante}!</strong> Organización: <strong>${agente.organizacion}</strong> — ${agente.zona}`;

    // Escuchar contador de caracteres
    const ideaTextarea = document.getElementById('ideaTexto');
    ideaTextarea.addEventListener('input', () => {
        document.getElementById('char-counter').textContent = ideaTextarea.value.length;
    });

    feedback.innerHTML = `<div class="alert alert-success py-2"><i class="fas fa-check-circle me-2"></i><strong>¡Verificado!</strong> Puedes continuar.</div>`;
    // Cargar ideas sugeridas del radar (leemos de dbProyectos que incluye las simuladas y las nuevas)
    const dbProyectosRadar = JSON.parse(localStorage.getItem('dbProyectos') || '[]');
    const ideasZona = dbProyectosRadar.filter(r => r.zona === agente.zona || r.zona === agente.sector).sort((a,b) => b.votos - a.votos).slice(0, 3);
    
    const radarContainer = document.getElementById('radar-ideas-sugeridas');
    if (radarContainer) {
        if (ideasZona.length > 0) {
            radarContainer.innerHTML = `
                <div class="card border-warning shadow-sm mb-3">
                    <div class="card-header bg-warning text-dark fw-bold">
                        <i class="fas fa-lightbulb me-2"></i>Ideas más votadas por tus vecinos en la ${agente.zona || agente.sector}
                    </div>
                    <ul class="list-group list-group-flush">
                        ${ideasZona.map(idea => `
                            <li class="list-group-item d-flex justify-content-between align-items-center">
                                <div class="pe-3">
                                    <span class="badge bg-secondary me-2">${idea.categoria || idea.cat}</span>
                                    <span class="text-muted fst-italic">"${idea.titulo || idea.problema || idea.texto}"</span>
                                    <span class="badge bg-success ms-2"><i class="fas fa-arrow-up me-1"></i>${idea.votos} votos</span>
                                </div>
                                <button class="btn btn-sm btn-outline-primary fw-bold text-nowrap" onclick="usarIdeaRadar('${(idea.titulo || idea.problema || idea.texto).replace(/'/g, "\\\\'")}')">Usar esta idea</button>
                            </li>
                        `).join('')}
                    </ul>
                </div>
            `;
        } else {
            radarContainer.innerHTML = '';
        }
    }

    setTimeout(() => wizardGoTo(2), 900);
}

